// ═══════════════════════════════════════════════════════
//  FLASHCARD DATA
// ═══════════════════════════════════════════════════════
const CARDS = [
  // ══════════════════════════════════════════════
  // Kap 1 – Ämnen, faser och reaktioner
  // ══════════════════════════════════════════════
  { id:535, cat:"Ämnen, faser och reaktioner", term:"Ämne", def:"Allt som har massa och tar upp plats; delas in i rena ämnen (grundämnen och kemiska föreningar) och blandningar." },
  { id:521, cat:"Ämnen, faser och reaktioner", term:"Materia", def:"Det generella begreppet för allt som har massa och volym; innefattar alla ämnen och blandningar i universum." },
  { id:522, cat:"Ämnen, faser och reaktioner", term:"Material", def:"Ett ämne eller en blandning av ämnen som används för ett tekniskt eller praktiskt syfte, t.ex. stål, trä, plast." },
  { id:527, cat:"Ämnen, faser och reaktioner", term:"Rent ämne", def:"Ämne med enhetlig, fast sammansättning; antingen ett grundämne eller en kemisk förening. Har skarpa smält- och kokpunkter." },
  { id:516, cat:"Ämnen, faser och reaktioner", term:"Kemisk förening", def:"Ämne uppbyggt av två eller fler grundämnen i fast förhållande, kemiskt bundna till varandra; kan bara sönderdelas med kemiska metoder. Exempel: vatten (H₂O), koksalt (NaCl)." },
  { id:528, cat:"Ämnen, faser och reaktioner", term:"Sammansatt ämne", def:"Synonymt med kemisk förening; ett ämne vars molekyler innehåller atomer av fler än ett grundämne." },
  { id:92,  cat:"Ämnen, faser och reaktioner", term:"Grundämne", def:"Rent ämne som inte kan sönderdelas i enklare ämnen med kemiska metoder; definieras av atomnumret (antal protoner)." },
  { id:501, cat:"Ämnen, faser och reaktioner", term:"Blandning", def:"Kombination av två eller fler ämnen som inte är kemiskt bundna; kan separeras med fysikaliska metoder. Delas in i homogena och heterogena blandningar." },
  { id:257, cat:"Ämnen, faser och reaktioner", term:"Homogen blandning", def:"Blandning med enhetlig sammansättning genomgående; faserna kan inte urskiljas. Exempel: saltlösning, luft, legering." },
  { id:258, cat:"Ämnen, faser och reaktioner", term:"Heterogen blandning", def:"Blandning med varierande sammansättning; olika faser är synliga. Exempel: sand i vatten, granit, mjölk. Kan separeras med filtrering eller dekantation." },
  { id:523, cat:"Ämnen, faser och reaktioner", term:"Partikel", def:"Minsta deltagande enhet i ett kemiskt sammanhang; kan vara atom, jon, molekyl eller formelenhet beroende på ämnestyp." },
  { id:503, cat:"Ämnen, faser och reaktioner", term:"Densitet", def:"Massa per volymenhet: ρ = m/V (kg/m³ eller g/cm³). Karakteristisk egenskap för ett ämne vid given temperatur och tryck. Vatten: 1 000 kg/m³ vid 4 °C." },
  { id:515, cat:"Ämnen, faser och reaktioner", term:"Karaktäristisk egenskap", def:"Egenskap som är unik för ett ämne och kan användas för att identifiera det, t.ex. densitet, smältpunkt, kokpunkt, löslighet och reaktivitet." },
  { id:505, cat:"Ämnen, faser och reaktioner", term:"Fas", def:"Homogen del av ett system med enhetliga egenskaper; t.ex. fast fas, flytande fas eller gasfas. En lösning är en enda fas." },
  { id:506, cat:"Ämnen, faser och reaktioner", term:"Fasgräns", def:"Gränsyta mellan två faser; t.ex. vatten–is eller vatten–luft. Vid fasgränsen sker fasövergångar." },
  { id:509, cat:"Ämnen, faser och reaktioner", term:"Fasövergång", def:"Förändring av ett ämnes aggregationstillstånd, t.ex. smältning, kokning, kondensation, sublimering, deposition eller stelning." },
  { id:300, cat:"Ämnen, faser och reaktioner", term:"Aggregationsform", def:"Ett ämnes fysikaliska form: fast, flytande eller gas. Bestäms av temperaturen och trycket. Kallas även aggregationstillstånd." },
  { id:507, cat:"Ämnen, faser och reaktioner", term:"Fast form", def:"Aggregationsform där partiklarna sitter i ett ordnat gitter med fasta positioner; bestämd form och volym. Exemplen: is, salt, metaller." },
  { id:510, cat:"Ämnen, faser och reaktioner", term:"Flytande form", def:"Aggregationsform där partiklarna är rörliga men tätt packade; bestämd volym men inte bestämd form. Exempel: vatten, kvicksilver." },
  { id:513, cat:"Ämnen, faser och reaktioner", term:"Gasform", def:"Aggregationsform där partiklarna rör sig fritt och fyller hela behållaren; varken bestämd form eller volym. Exempel: vattenånga, luft." },
  { id:508, cat:"Ämnen, faser och reaktioner", term:"Fast lösning", def:"Homogen blandning i fast form, t.ex. en legering; ett ämne är löst i ett annat fast ämne." },
  { id:286, cat:"Ämnen, faser och reaktioner", term:"Legering", def:"Fast lösning (blandkristall) av metaller. Exempel: brons (Cu+Sn), mässing (Cu+Zn), rostfritt stål (Fe+Cr+Ni)." },
  { id:301, cat:"Ämnen, faser och reaktioner", term:"Smältning", def:"Fasövergång fast → flytande när temperaturen når smältpunkten; endoterm (ΔH_fus > 0)." },
  { id:308, cat:"Ämnen, faser och reaktioner", term:"Smältpunkt", def:"Temperaturen vid vilken ett rent ämne övergår från fast till flytande form vid standardtryck. Karakteristisk och konstant för varje rent ämne." },
  { id:511, cat:"Ämnen, faser och reaktioner", term:"Frysning", def:"Fasövergång flytande → fast; exoterm (ΔH = −ΔH_fus < 0). Sker vid smält-/fryspunkten." },
  { id:512, cat:"Ämnen, faser och reaktioner", term:"Fryspunkt", def:"Temperaturen vid vilken ett ämne övergår från flytande till fast form vid standardtryck; sammanfaller med smältpunkten för rena ämnen." },
  { id:531, cat:"Ämnen, faser och reaktioner", term:"Stelningspunkt", def:"Synonymt med fryspunkt; temperaturen vid vilken en vätska stelnar till fast form. Stelningspunkten är lika med smältpunkten." },
  { id:302, cat:"Ämnen, faser och reaktioner", term:"Stelning", def:"Fasövergång flytande → fast; exoterm. Sker vid smältpunkten – samma temperatur som smältning, men omvänd riktning." },
  { id:518, cat:"Ämnen, faser och reaktioner", term:"Kokning", def:"Fasövergång flytande → gas när ångans tryck når omgivningens tryck; sker vid kokpunkten. Endoterm." },
  { id:303, cat:"Ämnen, faser och reaktioner", term:"Ångbildning", def:"Fasövergång flytande → gas vid kokpunkten (kokning) eller under kokpunkten (avdunstning). Endoterm: ΔH_vap > 0." },
  { id:309, cat:"Ämnen, faser och reaktioner", term:"Kokpunkt", def:"Temperaturen vid vilken ett ämnes ångtryck är lika med omgivningens tryck. Vatten: 100 °C vid 1 atm. Beror på trycket." },
  { id:534, cat:"Ämnen, faser och reaktioner", term:"Ånga", def:"Gas bildad från ett ämne som normalt är flytande eller fast vid rumstemperatur; t.ex. vattenånga (H₂O i gasform)." },
  { id:304, cat:"Ämnen, faser och reaktioner", term:"Kondensation", def:"Fasövergång gas → flytande; exoterm. Sker när ångans temperatur sjunker under daggpunkten. Exempel: imma på spegel, dagg." },
  { id:144, cat:"Ämnen, faser och reaktioner", term:"Avdunstning", def:"Fasövergång flytande → gas vid temperaturer UNDER kokpunkten, från ytan. Endoterm; har avkylande effekt." },
  { id:306, cat:"Ämnen, faser och reaktioner", term:"Sublimering", def:"Fasövergång fast → gas direkt, utan flytande mellanfas; endoterm. Exempel: torris (CO₂), jod, naftalin." },
  { id:307, cat:"Ämnen, faser och reaktioner", term:"Deposition", def:"Fasövergång gas → fast direkt, utan flytande mellanfas; exoterm. Exempel: frost som bildas direkt ur vattenånga." },
  { id:533, cat:"Ämnen, faser och reaktioner", term:"Värmerörelse", def:"Rörelsen hos partiklar i ett ämne orsakad av termisk energi; ökar med temperaturen. Förklarar diffusion, avdunstning och tryck i gaser." },
  { id:514, cat:"Ämnen, faser och reaktioner", term:"Indunstning", def:"Separationsmetod där ett lösningsmedel avdunstas (vanligtvis vatten) vid upphettning tills det lösta ämnet återstår som fast substans." },
  { id:62,  cat:"Ämnen, faser och reaktioner", term:"Lösning", def:"Homogen blandning av ett lösningsmedel och ett eller flera lösta ämnen; ser enhetlig ut genomgående." },
  { id:71,  cat:"Ämnen, faser och reaktioner", term:"Suspension", def:"Blandning där stora, olösliga partiklar är tillfälligt fördelade i ett medium; sedimenterar vid stillastående. Exempel: lera i vatten." },
  { id:312, cat:"Ämnen, faser och reaktioner", term:"Kolloid", def:"Blandning med partiklar 1–1 000 nm jämnt fördelade i ett dispersionsmedium. Visar Tyndalleffekten (ljusspridning). Sedimenterar ej spontant. Exempel: mjölk, rök, dimma." },
  { id:529, cat:"Ämnen, faser och reaktioner", term:"Sedimentering", def:"Process där tyngre partiklar i en suspension sjunker till botten under tyngdkraftens påverkan; används för att separera heterogena blandningar." },
  { id:502, cat:"Ämnen, faser och reaktioner", term:"Dekantering", def:"Separationsmetod där klar vätska hälls av från sedimentet utan att störa det fasta ämnet i botten." },
  { id:530, cat:"Ämnen, faser och reaktioner", term:"Separation", def:"Allmänt begrepp för att skilja ämnena i en blandning åt med fysikaliska metoder, t.ex. filtrering, destillation, kristallisering, avdunstning." },
  { id:80,  cat:"Ämnen, faser och reaktioner", term:"Destillation", def:"Separationsmetod baserad på skillnader i kokpunkt; vätskan värms, ångan kondenseras och samlas separat." },
  { id:81,  cat:"Ämnen, faser och reaktioner", term:"Filtrering", def:"Separationsmetod för att avskilja fasta partiklar från en vätska med hjälp av ett poröst medium (filterpapper)." },
  { id:82,  cat:"Ämnen, faser och reaktioner", term:"Kristallisering", def:"Separationsmetod där ett löst ämne separeras genom att bilda fasta kristaller vid avkylning eller avdunstning av lösningsmedel." },
  { id:536, cat:"Ämnen, faser och reaktioner", term:"Fällning", def:"Bildning av ett fast, olösligt ämne (precipitat/fällning) ur en lösning, t.ex. när två jonlösningar blandas. Avskiljs med filtrering." },
  { id:500, cat:"Ämnen, faser och reaktioner", term:"Analys", def:"Undersökning för att bestämma ett ämnes sammansättning eller egenskaper. Delas i kvalitativ analys (vad?) och kvantitativ analys (hur mycket?)." },
  { id:519, cat:"Ämnen, faser och reaktioner", term:"Kvalitativ analys", def:"Analytisk metod som identifierar VILKA ämnen som finns i ett prov, t.ex. flammtest för metallkatjoner eller indikatortest för syror/baser." },
  { id:520, cat:"Ämnen, faser och reaktioner", term:"Kvantitativ analys", def:"Analytisk metod som bestämmer HUR MYCKET av ett ämne som finns i ett prov, t.ex. via titrering, gravimetri eller spektroskopi." },
  { id:517, cat:"Ämnen, faser och reaktioner", term:"Kemisk reaktion", def:"Process där utgångsämnena (reaktanterna) omvandlas till nya ämnen (produkterna) via ombildning av kemiska bindningar; massa bevaras." },
  { id:524, cat:"Ämnen, faser och reaktioner", term:"Produkt", def:"Det eller de ämnen som bildas i en kemisk reaktion; skrivs till höger om pilen i reaktionsformeln." },
  { id:525, cat:"Ämnen, faser och reaktioner", term:"Reaktant", def:"Utgångsämne i en kemisk reaktion; förbrukas under reaktionen. Skrivs till vänster om pilen i reaktionsformeln." },
  { id:532, cat:"Ämnen, faser och reaktioner", term:"Utgångsämne", def:"Synonymt med reaktant; det ämne som förbrukas i en kemisk reaktion och omvandlas till produkter." },
  { id:526, cat:"Ämnen, faser och reaktioner", term:"Reagens", def:"Ämne som används för att åstadkomma en kemisk reaktion eller för att påvisa närvaron av ett specifikt ämne, t.ex. en indikator." },
  { id:504, cat:"Ämnen, faser och reaktioner", term:"Energiprincipen", def:"Energi varken skapas eller förstörs; den omvandlas mellan olika former (kemisk, termisk, mekanisk). Energin är bevarad i ett isolerat system." },
  { id:109, cat:"Ämnen, faser och reaktioner", term:"Kombinationsreaktion", def:"Reaktionstyp där två eller fler ämnen förenas och bildar ett enda nytt ämne: A + B → AB. Exempel: 2H₂ + O₂ → 2H₂O." },
  { id:110, cat:"Ämnen, faser och reaktioner", term:"Sönderdelningsreaktion", def:"Reaktionstyp där ett ämne bryts ned till enklare ämnen: AB → A + B. Exempel: 2H₂O₂ → 2H₂O + O₂." },
  { id:380, cat:"Ämnen, faser och reaktioner", term:"Syntesreaktion", def:"Reaktionstyp (synonym med kombinationsreaktion) där ämnen förenas till ett nytt ämne. Exempel: N₂ + 3H₂ → 2NH₃." },
  { id:108, cat:"Ämnen, faser och reaktioner", term:"Fällningsreaktion", def:"Reaktion där ett svårlösligt salt (fällning) bildas när två jonlösningar blandas; t.ex. AgNO₃ + NaCl → AgCl↓ + NaNO₃." },
  { id:145, cat:"Ämnen, faser och reaktioner", term:"Blandbarhet", def:"Förmågan hos två vätskor att blanda sig i alla proportioner utan fasuppdelning; t.ex. etanol och vatten är blandbara, men olja och vatten inte." },

  // ══════════════════════════════════════════════
  // Kap 2 – Kemins arbetsmetoder
  // ══════════════════════════════════════════════
  { id:600, cat:"Kemins arbetsmetoder", term:"Vetenskap", def:"Systematisk verksamhet för att bygga och organisera kunskap om världen via observationer, hypoteser, experiment och teorier." },
  { id:601, cat:"Kemins arbetsmetoder", term:"Naturvetenskap", def:"Vetenskap som studerar naturfenomen; bygger på empiriska metoder (observation och experiment) för att formulera modeller och teorier." },
  { id:602, cat:"Kemins arbetsmetoder", term:"Hypotes", def:"En testbar förklaring eller förutsägelse baserad på begränsad information; det nästa steget efter en observation. Testas via experiment." },
  { id:603, cat:"Kemins arbetsmetoder", term:"Alternativ hypotes", def:"En annan möjlig förklaring till ett observerat fenomen; vid experiment bör alternativa hypoteser utvärderas om resultaten inte stödjer den ursprungliga hypotesen." },
  { id:604, cat:"Kemins arbetsmetoder", term:"Teori", def:"Väl underbyggd förklaring stödd av upprepade experiment och oberoende verifieringar; mer robust än en hypotes. Kan aldrig bevisas sant för alltid, men kan motbevisas." },
  { id:605, cat:"Kemins arbetsmetoder", term:"Modell", def:"Förenklad representation av verkligheten som används för att förklara och förutsäga fenomen; t.ex. atommodellen, Bohrs modell, Lewis-struktur." },
  { id:606, cat:"Kemins arbetsmetoder", term:"Observation", def:"Insamling av data med sinnena eller mätinstrument utan tolkning; grunden för all vetenskaplig verksamhet. Skiljer sig från slutledning." },
  { id:607, cat:"Kemins arbetsmetoder", term:"Experiment", def:"Systematisk undersökning med kontrollerade variabler för att testa en hypotes; reproducerbart förfarande i labb eller fält." },
  { id:608, cat:"Kemins arbetsmetoder", term:"Systematisk undersökning", def:"Planerad undersökning med tydlig frågeställning, hypotes, kontrollerade variabler, datainsamling och analys för att dra slutsatser." },
  { id:609, cat:"Kemins arbetsmetoder", term:"Felkälla", def:"Faktor som kan påverka mätresultaten och ge ett felaktigt eller missvisande resultat; identifieras och minimeras i god experimentdesign." },
  { id:610, cat:"Kemins arbetsmetoder", term:"Dokumentation", def:"Noggrann skriftlig redovisning av metod, observationer, mätdata och slutsatser; möjliggör reproducerbarhet och granskning av andras arbete." },
  { id:611, cat:"Kemins arbetsmetoder", term:"Labbrapport", def:"Skriftlig redovisning av ett laboratorieexperiment; innehåller syfte, hypotes, material/metod, resultat, slutsatser och felkälldiskussion." },
  { id:612, cat:"Kemins arbetsmetoder", term:"Källkritik", def:"Kritisk granskning av informationskällors trovärdighet, relevans och objektivitet; viktig vid sökning av kemisk information." },
  { id:613, cat:"Kemins arbetsmetoder", term:"Objektiv kunskap", def:"Kunskap som är oberoende av den enskilda observatörens känslor och förutfattade meningar; baseras på reproducerbara mätningar och observationer." },
  { id:614, cat:"Kemins arbetsmetoder", term:"Subjektiv kunskap", def:"Kunskap som påverkas av individens erfarenheter, värderingar och perspektiv; kan leda till bias i tolkning av vetenskapliga data." },
  { id:615, cat:"Kemins arbetsmetoder", term:"Miljö", def:"I kemikontext: naturmiljön och hur kemiska ämnen och processer påverkar den; grön kemi syftar till att minska negativ miljöpåverkan." },
  { id:616, cat:"Kemins arbetsmetoder", term:"Risk", def:"Sannolikheten att en fara faktiskt orsakar skada; bedöms utifrån ämnets farlighet, exponeringsnivå och exponeringstid." },
  { id:84,  cat:"Kemins arbetsmetoder", term:"Riskbedömning", def:"Systematisk identifiering, bedömning och hantering av potentiella faror i laboratoriet innan arbetet påbörjas." },
  { id:87,  cat:"Kemins arbetsmetoder", term:"Faropiktogram", def:"Globalt harmoniserade symboler (röd romb, GHS) som varnar för kemiska risker: frätande, brandfarligt, giftigt, explosivt, miljöfarligt m.fl." },
  { id:88,  cat:"Kemins arbetsmetoder", term:"Säkerhetsdatablad (SDB)", def:"Dokument med information om ett kemiskt ämnes egenskaper, faror, skyddsåtgärder och nödprocedurer enligt EU-förordning REACH/CLP." },
  { id:85,  cat:"Kemins arbetsmetoder", term:"Skyddsutrustning", def:"Personlig skyddsutrustning (PSE) vid laboratoriearbete: skyddsglasögon, labbrock, kemikalietåliga handskar och vid behov andningsskydd." },
  { id:86,  cat:"Kemins arbetsmetoder", term:"Kemikaliesäkerhet", def:"Kunskap om och rätt hantering av farliga kemikalier inkl. förvaring, märkning och avfallshantering för att förebygga olyckor." },
  { id:375, cat:"Kemins arbetsmetoder", term:"Grön kemi", def:"Kemins 12 principer för att minimera miljöpåverkan: förebygg avfall, hög atomeffektivitet, använd ofarliga kemikalier, katalys och förnyelsebara råvaror." },
  { id:143, cat:"Kemins arbetsmetoder", term:"Gravimetrisk analys", def:"Kvantitativ analysmetod där ett ämne fälls ut, filtreras, torkas och vägs för att bestämma mängden i provet." },

  // ══════════════════════════════════════════════
  // Kap 3 – Atomer och periodiska systemet
  // ══════════════════════════════════════════════
  { id:1,   cat:"Atomer och periodiska systemet", term:"Atom", def:"Den minsta enheten av ett grundämne som behåller ämnets kemiska egenskaper; består av kärna (protoner + neutroner) och elektroner." },
  { id:700, cat:"Atomer och periodiska systemet", term:"Atomkärna", def:"Den centrala, täta delen av atomen som innehåller protoner och neutroner (nukleoner); har positiv laddning; upptar en liten del av atomens volym." },
  { id:4,   cat:"Atomer och periodiska systemet", term:"Atomnummer", def:"Antalet protoner i en atoms kärna; betecknas Z; definierar vilket grundämne det är och avgör plats i periodiska systemet." },
  { id:5,   cat:"Atomer och periodiska systemet", term:"Masstal", def:"Summan av antalet protoner och neutroner i en atoms kärna; betecknas A. A = Z + N (antal neutroner)." },
  { id:7,   cat:"Atomer och periodiska systemet", term:"Proton", def:"Positivt laddad partikel i atomkärnan; antalet protoner (Z) avgör vilket grundämne det är." },
  { id:8,   cat:"Atomer och periodiska systemet", term:"Neutron", def:"Oladdad partikel i atomkärnan; bidrar till massan men inte till laddningen; stabiliserar kärnan." },
  { id:6,   cat:"Atomer och periodiska systemet", term:"Elektron", def:"Negativt laddad partikel (−1,6×10⁻¹⁹ C) i skal runt atomkärnan; bidrar till kemiska reaktioner." },
  { id:701, cat:"Atomer och periodiska systemet", term:"Kärnpartikel", def:"Gemensamt namn för protoner och neutroner i atomkärnan; kallas även nukleoner." },
  { id:702, cat:"Atomer och periodiska systemet", term:"Elementarpartikel", def:"Grundläggande beståndsdel av materian; proton, neutron och elektron är de tre viktigaste i kemin." },
  { id:703, cat:"Atomer och periodiska systemet", term:"Elementarladdning", def:"Den minsta fria laddningsenheten: e = 1,602×10⁻¹⁹ C. Protonen har laddningen +e, elektronen −e." },
  { id:704, cat:"Atomer och periodiska systemet", term:"Laddning", def:"Fysikalisk egenskap hos partiklar; proton = +1, elektron = −1, neutron = 0. Lika laddningar repellerar; olika attraherar." },
  { id:3,   cat:"Atomer och periodiska systemet", term:"Isotop", def:"Atomer av samma grundämne med samma antal protoner men olika antal neutroner, och därmed olika masstal." },
  { id:715, cat:"Atomer och periodiska systemet", term:"Atommassa (atomnivå)", def:"Massa hos en enstaka atom uttryckt i atommassenheter (u); relateras till relativ atommassa Aᵣ. Proton ≈ 1 u, neutron ≈ 1 u, elektron ≈ 0,0005 u." },
  { id:388, cat:"Atomer och periodiska systemet", term:"Relativ atommassa", def:"Synonymt med atommassa; viktat medelvärde av isotopmassor relativt ¹²C = 12,000. Beräknas: Aᵣ = Σ(isotopandel × isotopmassal)." },
  { id:9,   cat:"Atomer och periodiska systemet", term:"Elektronskal", def:"Energinivå runt atomkärnan där elektroner befinner sig; betecknas K, L, M… eller n = 1, 2, 3… Varje skal rymmer max 2n² elektroner." },
  { id:10,  cat:"Atomer och periodiska systemet", term:"Elektronkonfiguration", def:"Fördelningen av elektroner i ett atoms energiskal, t.ex. natrium: 2, 8, 1." },
  { id:91,  cat:"Atomer och periodiska systemet", term:"Orbitaler", def:"Matematisk funktion som beskriver sannolikhetsfördelningen för en elektron; benämns s, p, d och f. Varje orbital rymmer max 2 elektroner." },
  { id:705, cat:"Atomer och periodiska systemet", term:"Energinivå", def:"Bestämd energi som en elektron kan ha i en atom; elektroner befinner sig alltid på diskreta energinivåer (kvantisering)." },
  { id:265, cat:"Atomer och periodiska systemet", term:"Valenselektron", def:"Elektron i atomens yttersta skal; bestämmer kemiska egenskaper och reaktivitet. Antal valenselektroner = gruppnummer (huvudgrupp)." },
  { id:266, cat:"Atomer och periodiska systemet", term:"Exciterad atom", def:"Atom där en elektron har absorberats energi och hoppat till ett högre skal. När elektronen faller tillbaka avges energin som ljus med specifik våglängd." },
  { id:706, cat:"Atomer och periodiska systemet", term:"Energi (atom)", def:"I atomkontext: elektroner kan bara absorbera eller avge energi i diskreta kvanta (fotoner); detta förklarar atomers spektrallinjer." },
  { id:387, cat:"Atomer och periodiska systemet", term:"Bohrs atommodell", def:"Niels Bohrs (1913) modell: elektroner rör sig i fasta cirkelbanor med bestämda energier; elektron kan hoppa mellan banor via absorption/emission av foton." },
  { id:707, cat:"Atomer och periodiska systemet", term:"Rutherfords atommodell", def:"Ernest Rutherfords (1911) modell: atomen har en liten, tät, positivt laddad kärna omgiven av elektroner på stort avstånd; baseras på guldfolieexperimentet." },
  { id:708, cat:"Atomer och periodiska systemet", term:"Schrödingers atommodell", def:"Modern kvantmekanisk modell (1926) som beskriver elektroner som sannolikhetsmolnar (orbitaler) snarare än fasta banor; mer korrekt än Bohrs modell." },
  { id:83,  cat:"Atomer och periodiska systemet", term:"Spektroskopi och emissionsspektra", def:"Analytisk teknik baserad på ljusabsorption/-emission; varje grundämne har ett unikt emissionsspektrum (flamfärg) som beror på elektronövergångar." },
  { id:140, cat:"Atomer och periodiska systemet", term:"Flamfärgsreaktion", def:"Identifieringstest för metallkatjoner: lösningen förs in i gaslåga och karakteristisk färg avslöjar grundämnet. Na = gult, K = lila, Cu = grönt, Li = rött." },
  { id:714, cat:"Atomer och periodiska systemet", term:"Periodiska systemet", def:"Ordnat schema över grundämnena efter stigande atomnummer; uppvisar periodiska egenskaper (elektronegativitet, atomradie, ionisationsenergi) i rader (perioder) och kolumner (grupper)." },
  { id:11,  cat:"Atomer och periodiska systemet", term:"Periodicitet", def:"Det återkommande mönstret av egenskaper (atomradie, jonisationsenergi, elektronegativitet) hos grundämnen i periodiska systemet." },
  { id:267, cat:"Atomer och periodiska systemet", term:"Alkalimetaller", def:"Grupp 1; 1 valenselektron; avger den lätt → reagerar livligt med vatten och luft. Li, Na, K, Rb, Cs, Fr. Reaktiviteten ökar nedåt i gruppen." },
  { id:270, cat:"Atomer och periodiska systemet", term:"Alkaliska jordartsmetaller", def:"Grupp 2; 2 valenselektroner; reaktiva men mindre än alkalimetaller. Be, Mg, Ca, Sr, Ba, Ra. Ca och Mg viktiga i biologi och byggmaterial." },
  { id:268, cat:"Atomer och periodiska systemet", term:"Halogener", def:"Grupp 17; 7 valenselektroner; saknar ett för ädelgasstruktur → starka oxidationsmedel. F₂, Cl₂, Br₂, I₂. Oxiderande förmåga avtar nedåt i gruppen." },
  { id:269, cat:"Atomer och periodiska systemet", term:"Ädelgaser", def:"Grupp 18; fulla elektronskal (oktettkonfiguration); reagerar extremt sällan. He, Ne, Ar, Kr, Xe, Rn. Används som inerta atmosfärer och i ljusrör." },
  { id:709, cat:"Atomer och periodiska systemet", term:"Sällsynta jordartsmetaller", def:"Grupp av 17 grundämnen (lantanider + Sc, Y); liknande kemiska egenskaper. Viktiga i moderna teknologier (magneter, batterier, elektronik)." },
  { id:710, cat:"Atomer och periodiska systemet", term:"Övergångsmetaller", def:"Grundämnen i d-blocket (grupp 3–12); har delvis fyllt d-skal; bildar ofta färgade joner och kan ha flera oxidationstal. Exempel: Fe, Cu, Zn." },
  { id:14,  cat:"Atomer och periodiska systemet", term:"Metallkaraktär", def:"Egenskapen att ge ifrån sig elektroner och bilda positiva joner; ökar nedåt och åt vänster i periodiska systemet." },
  { id:93,  cat:"Atomer och periodiska systemet", term:"Atomradie", def:"Halvt avstånd mellan kärnorna i två bindande atomer av samma grundämne; minskar åt höger och ökar nedåt i periodiska systemet." },
  { id:89,  cat:"Atomer och periodiska systemet", term:"Radioaktivt ämne", def:"Ämne vars atomkärnor genomgår spontant sönderfall med utsändning av strålning (alfa, beta eller gamma); instabila isotoper." },
  { id:90,  cat:"Atomer och periodiska systemet", term:"Halveringstid", def:"Den tid det tar för hälften av atomkärnorna i ett radioaktivt prov att sönderfalla; konstant för varje isotop. Exempel: C-14: 5 730 år." },
  { id:711, cat:"Atomer och periodiska systemet", term:"Strålning", def:"Energiutsändning från radioaktiva ämnen; de tre typerna är alfastrålning (heliumkärnor), betastrålning (elektroner) och gammastrålning (fotoner)." },
  { id:271, cat:"Atomer och periodiska systemet", term:"Alfapartikel", def:"Heliumkärna (2 protoner + 2 neutroner) utsänd vid alfasönderfall; laddad +2; räckvidd ~10 cm i luft; stoppas av papper eller hud." },
  { id:272, cat:"Atomer och periodiska systemet", term:"Betastrålning", def:"Elektroner (β⁻) eller positroner (β⁺) som bildas vid kärnomvandling; räckvidd ~1 m i luft; stoppas av aluminium." },
  { id:273, cat:"Atomer och periodiska systemet", term:"Gammastrålning", def:"Elektromagnetisk strålning med mycket kort våglängd och hög energi; oladdad; kräver bly eller betong för att stoppas; mest penetrerande typ." },
  { id:712, cat:"Atomer och periodiska systemet", term:"¹⁴C-metoden", def:"Radiometrisk dateringsmetod baserad på halveringstiden för ¹⁴C (5 730 år); används för att datera organiska material upp till ~50 000 år gamla." },
  { id:713, cat:"Atomer och periodiska systemet", term:"Tvåatomig molekyl", def:"Molekyl bestående av exakt två atomer; kan vara homoatomig (H₂, O₂, N₂, Cl₂) eller heteroatomig (HCl, CO). Grundläggande molekyltyp." },
  { id:25,  cat:"Atomer och periodiska systemet", term:"Reaktionsformel", def:"Kemisk ekvation som visar reaktanter (vänster) och produkter (höger) med korrekt balanserade koefficienter och fasangivelser (s, l, g, aq)." },
  { id:94,  cat:"Atomer och periodiska systemet", term:"Ädelgasregeln", def:"Atomer strävar mot att uppnå ädelgasernas elektronconfiguration (8 elektroner i yttersta skalet, oktett) via bindningar; förklarar bindningsvalensen." },

  { id:200, cat:"Atomer och periodiska systemet", term:"H – Väte (Z=1)", def:"Lättaste grundämnet. Tvåatomig gas H₂. Period 1, grupp 1. Ingår i vatten och alla organiska molekyler." },
  { id:201, cat:"Atomer och periodiska systemet", term:"He – Helium (Z=2)", def:"Ädelgas. Reaktionströg. Lägst kokpunkt (−269 °C). Period 1, grupp 18." },
  { id:202, cat:"Atomer och periodiska systemet", term:"Li – Litium (Z=3)", def:"Lättaste metallen. Alkalimetall, grupp 1, period 2. 1 valenselektron. Bildar Li⁺." },
  { id:203, cat:"Atomer och periodiska systemet", term:"Be – Beryllium (Z=4)", def:"Jordalkalimetall, grupp 2, period 2. 2 valenselektroner. Bildar Be²⁺. Giftig." },
  { id:204, cat:"Atomer och periodiska systemet", term:"B – Bor (Z=5)", def:"Halvmetall, grupp 13, period 2. 3 valenselektroner. Ingår i Pyrex-glas." },
  { id:205, cat:"Atomer och periodiska systemet", term:"C – Kol (Z=6)", def:"Icke-metall, grupp 14, period 2. 4 valenselektroner. Grund för all organisk kemi. Allotroper: grafit och diamant." },
  { id:206, cat:"Atomer och periodiska systemet", term:"N – Kväve (Z=7)", def:"Icke-metall, grupp 15, period 2. Tvåatomig gas N₂ (78 % av luften). Trippelbindning i N₂." },
  { id:207, cat:"Atomer och periodiska systemet", term:"O – Syre (Z=8)", def:"Icke-metall, grupp 16, period 2. Tvåatomig gas O₂ (21 % av luften). Nödvändig för förbränning och andning." },
  { id:208, cat:"Atomer och periodiska systemet", term:"F – Fluor (Z=9)", def:"Halogen, grupp 17, period 2. Högst elektronegativitet (EN = 4,0). Starkt oxidationsmedel." },
  { id:209, cat:"Atomer och periodiska systemet", term:"Ne – Neon (Z=10)", def:"Ädelgas, grupp 18, period 2. 8 valenselektroner (fullt skal). Reaktionströg. Används i neonskyltar." },
  { id:210, cat:"Atomer och periodiska systemet", term:"Na – Natrium (Z=11)", def:"Alkalimetall, grupp 1, period 3. 1 valenselektron. Bildar Na⁺. Reagerar med vatten. Ingår i NaCl." },
  { id:211, cat:"Atomer och periodiska systemet", term:"Mg – Magnesium (Z=12)", def:"Jordalkalimetall, grupp 2, period 3. Bildar Mg²⁺. Ingår i klorofyll. Brinner med vitt ljus." },
  { id:212, cat:"Atomer och periodiska systemet", term:"Al – Aluminium (Z=13)", def:"Lättmetall, grupp 13, period 3. Bildar Al³⁺. Skyddande oxidhinna Al₂O₃ (passivering)." },
  { id:213, cat:"Atomer och periodiska systemet", term:"Si – Kisel (Z=14)", def:"Halvledare, grupp 14, period 3. Grunden för datorchip. Kvartssand = SiO₂." },
  { id:214, cat:"Atomer och periodiska systemet", term:"P – Fosfor (Z=15)", def:"Icke-metall, grupp 15, period 3. Vit (reaktiv) och röd form. Ingår i DNA och ATP." },
  { id:215, cat:"Atomer och periodiska systemet", term:"S – Svavel (Z=16)", def:"Icke-metall, grupp 16, period 3. Gul fast substans. Ingår i H₂SO₄ och aminosyror." },
  { id:216, cat:"Atomer och periodiska systemet", term:"Cl – Klor (Z=17)", def:"Halogen, grupp 17, period 3. Grön-gul gas Cl₂. Stark oxidant. Bildar Cl⁻." },
  { id:217, cat:"Atomer och periodiska systemet", term:"Ar – Argon (Z=18)", def:"Ädelgas, grupp 18, period 3. Vanligaste ädelgasen i atmosfären (~1 %). Skyddsgas vid svetsning." },
  { id:218, cat:"Atomer och periodiska systemet", term:"K – Kalium (Z=19)", def:"Alkalimetall, grupp 1, period 4. Bildar K⁺. Viktig i nervimpulser och växternas ämnesomsättning." },
  { id:219, cat:"Atomer och periodiska systemet", term:"Ca – Kalcium (Z=20)", def:"Jordalkalimetall, grupp 2, period 4. Bildar Ca²⁺. Ingår i kalksten (CaCO₃) och ben." },
  { id:220, cat:"Atomer och periodiska systemet", term:"Fe – Järn (Z=26)", def:"Övergångsmetall, period 4. Bildar Fe²⁺ och Fe³⁺. Vanligaste metallen i jordskorpan. Grunden för stål." },
  { id:221, cat:"Atomer och periodiska systemet", term:"Cu – Koppar (Z=29)", def:"Övergångsmetall, period 4. Bildar Cu⁺ och Cu²⁺. Utmärkt elektrisk ledare." },
  { id:222, cat:"Atomer och periodiska systemet", term:"Zn – Zink (Z=30)", def:"Övergångsmetall, period 4. Bildar Zn²⁺. Galvanisering av stål (rostskydd)." },
  { id:223, cat:"Atomer och periodiska systemet", term:"Br – Brom (Z=35)", def:"Halogen, period 4. Enda icke-metallen som är flytande vid rumstemperatur. Bildar Br⁻." },
  { id:224, cat:"Atomer och periodiska systemet", term:"Ag – Silver (Z=47)", def:"Ädel övergångsmetall. Bästa elektriska ledaren. Bildar Ag⁺." },
  { id:225, cat:"Atomer och periodiska systemet", term:"I – Jod (Z=53)", def:"Halogen, period 5. Svart-lila fast substans. Bildar I⁻. Viktigt för sköldkörteln." },
  { id:226, cat:"Atomer och periodiska systemet", term:"Au – Guld (Z=79)", def:"Ädel övergångsmetall. Bildar Au⁺ och Au³⁺. Löser sig inte i vanliga syror." },

  // ══════════════════════════════════════════════
  // Kap 4 – Kemiska bindningar
  // ══════════════════════════════════════════════
  { id:2,   cat:"Kemiska bindningar", term:"Jon", def:"En atom eller molekyl som har fått eller förlorat elektroner och därigenom blivit elektriskt laddad; katjon = positiv, anjon = negativ." },
  { id:800, cat:"Kemiska bindningar", term:"Atomjon", def:"Jon bildad av en enda atom som tagit upp eller avgivit elektroner; t.ex. Na⁺, Cl⁻, Ca²⁺. Skiljer sig från molekyljon som bildas av flera atomer." },
  { id:12,  cat:"Kemiska bindningar", term:"Elektronegativitet", def:"Ett grundämnes förmåga att attrahera elektroner i en kemisk bindning; ökar uppåt och åt höger i periodiska systemet. Fluor har högst EN (4,0)." },
  { id:13,  cat:"Kemiska bindningar", term:"Joniseringsenergi", def:"Den energi som krävs för att avlägsna en elektron från en fri atom i gasform; ökar uppåt och åt höger i periodiska systemet." },
  { id:15,  cat:"Kemiska bindningar", term:"Jonbindning", def:"Kemisk bindning genom elektrostatisk attraktion mellan positivt och negativt laddade joner; bildas när elektroner överförs från metall till icke-metall." },
  { id:801, cat:"Kemiska bindningar", term:"Elektronparbindning", def:"Synonymt med kovalent bindning; atomer delar ett eller flera elektronpar. Bindande elektronpar stabiliserar båda atomerna." },
  { id:16,  cat:"Kemiska bindningar", term:"Kovalent bindning", def:"Kemisk bindning där atomer delar ett eller flera elektronpar; vanlig mellan icke-metaller; kan vara polär eller opolär." },
  { id:802, cat:"Kemiska bindningar", term:"Bindande elektronpar", def:"Elektronpar som delas av två atomer och bildar en kovalent bindning; ger stabilitet via elektrostatisk attraktion mot båda kärnorna." },
  { id:803, cat:"Kemiska bindningar", term:"Icke-bindande elektronpar", def:"Elektronpar på en atom som inte deltar i bindning (ensamt par/lone pair); påverkar molekylens geometri (VSEPR) och reaktivitet." },
  { id:17,  cat:"Kemiska bindningar", term:"Metallbindning", def:"Bindning i metaller där positiva metalljoner omges av ett 'hav' av fria, rörliga elektroner; förklarar elektrisk och termisk ledningsförmåga." },
  { id:804, cat:"Kemiska bindningar", term:"Delokaliserade elektroner", def:"Elektroner som inte tillhör ett specifikt atompar utan rör sig fritt över ett helt system, t.ex. i metaller (elektronhav) eller grafit och bensen (π-elektroner)." },
  { id:18,  cat:"Kemiska bindningar", term:"Polär kovalent bindning", def:"Kovalent bindning där elektronerna delas ojämnt p.g.a. skillnad i elektronegativitet; skapar partiella laddningar (δ+ och δ−)." },
  { id:19,  cat:"Kemiska bindningar", term:"Opolär kovalent bindning", def:"Kovalent bindning där elektronerna delas jämnt mellan likartade atomer (t.ex. H₂, O₂); ingen nettoladdningsskillnad." },
  { id:805, cat:"Kemiska bindningar", term:"Polaritet", def:"Grad av ojämn laddningsfördelning i en bindning eller molekyl; bestäms av elektronegativitetsskillnaden. Polär molekyl: asymmetrisk laddningsfördelning." },
  { id:20,  cat:"Kemiska bindningar", term:"Dipol", def:"Molekyl eller bindning med separerade positiva och negativa laddningscentra (δ+ och δ−); vektoriellt mått på laddningsseparationen." },
  { id:294, cat:"Kemiska bindningar", term:"Enkelbindning", def:"Ett gemensamt elektronpar (σ-bindning) mellan två atomer; längst och svagast av kovalenta bindningarna. Exempel: H–H, C–C, H–Cl." },
  { id:295, cat:"Kemiska bindningar", term:"Dubbelbindning", def:"Två gemensamma elektronpar (1 σ + 1 π) mellan atomer; kortare och starkare än enkelbindning. Exempel: O=O, C=C i alkener." },
  { id:296, cat:"Kemiska bindningar", term:"Trippelbindning", def:"Tre gemensamma elektronpar (1 σ + 2 π); kortast och starkast. Exempel: N≡N (945 kJ/mol)." },
  { id:21,  cat:"Kemiska bindningar", term:"Vätebindning", def:"Stark intermolekylär kraft mellan ett väte bundet till N, O eller F och ett elektronnegativt atom i en annan molekyl; ger vatten högt kokpunkt." },
  { id:22,  cat:"Kemiska bindningar", term:"Van der Waalskrafter", def:"Svaga intermolekylära krafter orsakade av tillfälliga och inducerade dipoler (London-dispersion); ökar med molekylstorleken." },
  { id:389, cat:"Kemiska bindningar", term:"Dipol-dipolbindning", def:"Intermolekylär kraft mellan polära molekyler; de partiella laddningarna (δ+ och δ−) attraherar varandra. Starkare än van der Waals men svagare än vätebindning." },
  { id:100, cat:"Kemiska bindningar", term:"Intermolekylära krafter", def:"Krafter mellan molekyler (ej inom dem); innefattar vätebindningar, dipol-dipol-växelverkan och van der Waalskrafter. Avgör kokpunkt och löslighet." },
  { id:806, cat:"Kemiska bindningar", term:"Intramolekylär bindning", def:"Kemisk bindning INOM en molekyl (kovalent, jon- eller metallbindning); starkare än intermolekylära krafter." },
  { id:810, cat:"Kemiska bindningar", term:"Jon-dipolbindning", def:"Attraktion mellan en jon och en polär molekyls dipol; t.ex. hydratisering av joner i vatten. Starkare än rena dipol-dipolkrafter." },
  { id:807, cat:"Kemiska bindningar", term:"Hydratiserad jon", def:"Jon omgiven av vattenmolekyler via jon-dipolbindningar i vattenlösning; Na⁺ omges av O-sidan hos vatten, Cl⁻ av H-sidan." },
  { id:23,  cat:"Kemiska bindningar", term:"Strukturformel", def:"Schematisk bild av en molekyl som visar kovalenta bindningar som streck och fria elektronpar som punkter (Lewis-struktur)." },
  { id:24,  cat:"Kemiska bindningar", term:"Rymdstruktur", def:"Tredimensionell geometri hos en molekyl; förutsägs med VSEPR-modellen baserat på antalet elektronpar runt centralatomen." },
  { id:808, cat:"Kemiska bindningar", term:"Formelenhet", def:"Minsta enheten av ett jonämne som återger ämnets formel; t.ex. en formelenhet NaCl = ett Na⁺ och ett Cl⁻. Används istället för 'molekyl' för jonföreningar." },
  { id:99,  cat:"Kemiska bindningar", term:"Kristall", def:"Regelbunden, upprepad tredimensionell struktur av atomer, joner eller molekyler; innefattar jonkristaller (NaCl), metallkristaller och nätverkskovalenta kristaller (diamant)." },
  { id:297, cat:"Kemiska bindningar", term:"Diamant", def:"Nätverkskovalent kristall av kol; varje C-atom binder kovalent till 4 andra i tetraedergeometri → extremt hårt. Hög smältpunkt, leder inte ström." },
  { id:298, cat:"Kemiska bindningar", term:"Grafit", def:"Skiktat kol; varje C-atom binder till 3 andra i plana hexagonskikt. Fjärde valenselektronen delokaliserad → leder ström. Skikten hålls av svaga van der Waalskrafter." },
  { id:63,  cat:"Kemiska bindningar", term:"Lösningsmedel", def:"Det ämne som löser upp andra ämnen i en lösning; vanligtvis det ämne som finns i störst mängd. Polärt lösningsmedel (vatten) löser polära/joner; opolärt löser opolära." },
  { id:284, cat:"Kemiska bindningar", term:"Lika löser lika", def:"Polära ämnen löses i polära lösningsmedel (vatten); opolära i opolära (hexan, bensin). Beror på intermolekylärna krafterna." },
  { id:285, cat:"Kemiska bindningar", term:"Hydratisering", def:"Vattenmolekyler omger och stabiliserar joner i lösning via jon-dipolväxelverkan; möjliggör att jonföreningar löser sig i vatten." },
  { id:260, cat:"Kemiska bindningar", term:"Hydrofil", def:"'Vattenälskande'; polära ämnen (salter, socker, etanol) som löser sig i vatten via jon-dipol- eller vätebindningar." },
  { id:261, cat:"Kemiska bindningar", term:"Hydrofob", def:"'Vattenfrysande'; opolära ämnen (fetter, oljor, vaxer) som inte löser sig i vatten men löser sig i opolära lösningsmedel." },
  { id:139, cat:"Kemiska bindningar", term:"Kromatografi", def:"Separationsmetod baserad på ämneters olika affinitet för en stationär och en mobil fas; t.ex. TLC, papperskromatografi, HPLC. Separerar blandningar utan kemisk omvandling." },
  { id:101, cat:"Kemiska bindningar", term:"Jonradie", def:"Storlek på en jon i en kristall; anjoner är generellt större och katjoner mindre än motsvarande neutrala atom." },
  { id:809, cat:"Kemiska bindningar", term:"Ädelgasregeln (oktettregeln)", def:"Atomer strävar mot att ha 8 elektroner (4 elektronpar) i yttersta skalet vid bindning – samma som ädelgaser. H och He siktar på 2 elektroner (duplettregel)." },

  // ══════════════════════════════════════════════
  // Kap 5 – Organiska ämnen är kolföreningar
  // ══════════════════════════════════════════════
  { id:48,  cat:"Organiska ämnen är kolföreningar", term:"Kolväte", def:"Organisk förening som enbart innehåller kol och väte; delas in i alkaner, alkener, alkyner och arener." },
  { id:900, cat:"Organiska ämnen är kolföreningar", term:"Alifatiska kolväten", def:"Kolväten med öppna (ej aromatiska) kolkedjor; innefattar alkaner, alkener och alkyner. Kan vara raka, grenade eller cykliska." },
  { id:49,  cat:"Organiska ämnen är kolföreningar", term:"Alkan", def:"Mättat kolväte med enbart enkelbindningar; allmän formel CₙH₂ₙ₊₂. Exempel: metan (CH₄), etan (C₂H₆), propan (C₃H₈)." },
  { id:50,  cat:"Organiska ämnen är kolföreningar", term:"Alken", def:"Omättat kolväte med minst en C=C-dubbelbindning; allmän formel CₙH₂ₙ. Exempel: eten (C₂H₄), propen." },
  { id:51,  cat:"Organiska ämnen är kolföreningar", term:"Alkyn", def:"Omättat kolväte med minst en C≡C-trippelbindning; allmän formel CₙH₂ₙ₋₂. Exempel: etyn (acetylen, C₂H₂)." },
  { id:52,  cat:"Organiska ämnen är kolföreningar", term:"Aren", def:"Aromatiskt kolväte med minst en bensenkärna och delokaliserade π-elektroner; t.ex. bensen (C₆H₆), toluen." },
  { id:901, cat:"Organiska ämnen är kolföreningar", term:"Bensen", def:"Enklaste aromatiska kolvätet; C₆H₆. Hexagonal ring med delokaliserade elektroner → extra stabil. Cancerframkallande (CMR-ämne)." },
  { id:390, cat:"Organiska ämnen är kolföreningar", term:"Cykliskt kolväte", def:"Kolväte med kolatomerna i en ring; t.ex. cykloalkaner (CₙH₂ₙ: cyklohexan) och arener. Namnges med prefixet 'cyklo-'." },
  { id:53,  cat:"Organiska ämnen är kolföreningar", term:"Funktionell grupp", def:"Atomgrupp i en organisk molekyl som bestämmer ämnets typiska kemiska reaktioner och egenskaper; t.ex. –OH, –COOH, –NH₂." },
  { id:902, cat:"Organiska ämnen är kolföreningar", term:"Hydroxylgrupp", def:"Funktionell grupp –OH; karakteriserar alkoholer och fenoler. Ger möjlighet till vätebindningar → högt kokpunkt jämfört med liknande kolväten." },
  { id:903, cat:"Organiska ämnen är kolföreningar", term:"Karboxylgrupp", def:"Funktionell grupp –COOH; karakteriserar karboxylsyror. Är sur (avger H⁺) i vattenlösning." },
  { id:54,  cat:"Organiska ämnen är kolföreningar", term:"Alkohol", def:"Organisk förening med hydroxylgrupp (–OH) bunden till kolkedja. Envärd: ett –OH (etanol, C₂H₅OH). Tvåvärd: glycol. Trevärd: glycerol." },
  { id:55,  cat:"Organiska ämnen är kolföreningar", term:"Aldehyd", def:"Organisk förening med karbonylgrupp (–CHO) vid kedjans ände; t.ex. metanal (formaldehyd, HCHO). Kan oxideras till karboxylsyra." },
  { id:56,  cat:"Organiska ämnen är kolföreningar", term:"Keton", def:"Organisk förening med karbonylgrupp (C=O) i mitten av kolkedjan; t.ex. propanon (aceton). Kan ej oxideras vidare till syra." },
  { id:57,  cat:"Organiska ämnen är kolföreningar", term:"Karboxylsyra", def:"Organisk syra med karboxylgrupp (–COOH); ger surt pH i vattenlösning. Exempel: ättiksyra (CH₃COOH), citronsyra." },
  { id:58,  cat:"Organiska ämnen är kolföreningar", term:"Ester", def:"Organisk förening bildad av karboxylsyra och alkohol med avspjälkning av vatten; ofta välluktande. Exempel: etylacetat." },
  { id:60,  cat:"Organiska ämnen är kolföreningar", term:"Isomeri", def:"Fenomenet att föreningar med samma molekylformel har olika strukturer (konstitutionsisomerer) eller rumsorientering (stereoisomerer)." },
  { id:904, cat:"Organiska ämnen är kolföreningar", term:"Molekylformel", def:"Formel som visar hur många atomer av varje slag som ingår i en molekyl, t.ex. C₂H₅OH. Ger ingen information om strukturen." },
  { id:905, cat:"Organiska ämnen är kolföreningar", term:"Skelettformel", def:"Förenklad strukturformel där C-atomer representeras av hörn och linjer; H-atomer på kol utelämnas. Snabb och tydlig representation av organiska molekyler." },
  { id:61,  cat:"Organiska ämnen är kolföreningar", term:"Systematiskt namn", def:"IUPAC-baserat namngivningssystem för organiska föreningar; baseras på längsta kolkedja, grenar och funktionella grupper. Ger entydig identifiering." },
  { id:906, cat:"Organiska ämnen är kolföreningar", term:"Trivialnamn", def:"Historiskt/vardagligt namn på ett kemiskt ämne som inte följer IUPAC-reglerna; t.ex. ättiksyra (IUPAC: etansyra), aceton (propanon)." },
  { id:907, cat:"Organiska ämnen är kolföreningar", term:"Ämnesklass", def:"Grupp av organiska föreningar med samma funktionella grupp och liknande kemiska egenskaper; t.ex. alkoholer, karboxylsyror, alkaner." },
  { id:908, cat:"Organiska ämnen är kolföreningar", term:"Substituent", def:"Atom eller atomgrupp som ersätter ett väte i en organisk molekyl; t.ex. metyl (–CH₃), etyl (–C₂H₅) eller klor (–Cl)." },
  { id:118, cat:"Organiska ämnen är kolföreningar", term:"Additionsreaktion", def:"Reaktion där atomer eller grupper adderas till en dubbel- eller trippelbindning; omättad förening → mättad." },
  { id:119, cat:"Organiska ämnen är kolföreningar", term:"Substitutionsreaktion", def:"Reaktion där en atom eller grupp i en molekyl ersätts av en annan; vanlig för mättade kolväten och arener." },
  { id:120, cat:"Organiska ämnen är kolföreningar", term:"Kondensationsreaktion", def:"Reaktion där två molekyler förenas med avspjälkning av ett litet molekyl (vanligen H₂O); bildar t.ex. estrar och peptider." },
  { id:392, cat:"Organiska ämnen är kolföreningar", term:"Syntes", def:"Reaktion där ett organiskt ämne framställs från enklare utgångsämnen via kemiska reaktioner; t.ex. polymerisation, kondensation, esterbildning." },
  { id:121, cat:"Organiska ämnen är kolföreningar", term:"Polymer", def:"Stor makromolekyl uppbyggd av upprepande enheter (monomerer) bundna kovalent; t.ex. polyeten, nylon, gummi." },
  { id:122, cat:"Organiska ämnen är kolföreningar", term:"Monomer", def:"Liten molekyl som kan länkas ihop med andra monomerer för att bilda en polymer via polymerisationsreaktion." },
  { id:909, cat:"Organiska ämnen är kolföreningar", term:"CMR-ämne", def:"Kemikalie klassad som cancerframkallande (Carcinogenic), mutagent (Mutagenic) eller reproduktionstoxiskt (Reprotoxic); kräver särskild försiktighet; t.ex. bensen." },
  { id:279, cat:"Organiska ämnen är kolföreningar", term:"Fossilt bränsle", def:"Bränsle bildat av organiska rester under 100-tals miljoner år: kol, olja och naturgas. Förbränning frigör CO₂ som länge lagrats → bidrar till växthuseffekten." },
  { id:280, cat:"Organiska ämnen är kolföreningar", term:"Biobränsle", def:"Förnybart bränsle från biomassa: etanol (jäsning av socker), metan (förruttnelse), ved. CO₂-neutralt i teorin (CO₂ frigjort = CO₂ upptagit av växten)." },

  // ══════════════════════════════════════════════
  // Kap 6 – Kemiska beräkningar
  // ══════════════════════════════════════════════
  { id:1000, cat:"Kemiska beräkningar", term:"Storhet", def:"Mätbar fysikalisk egenskap; t.ex. massa, volym, substansmängd, koncentration. Uttrycks som ett mätetal gånger en enhet." },
  { id:1001, cat:"Kemiska beräkningar", term:"Enhet", def:"Referensvärde för en storhet; t.ex. kg för massa, L för volym, mol för substansmängd. SI-systemet är standard inom kemin." },
  { id:1002, cat:"Kemiska beräkningar", term:"Mätetal", def:"Det numeriska värdet av en storhet i förhållande till en vald enhet. Storhet = mätetal × enhet, t.ex. m = 5,0 g." },
  { id:290, cat:"Kemiska beräkningar", term:"Substansmängd", def:"Antal mol av ett ämne: n = m / M. 1 mol = 6,022×10²³ partiklar. Enheten är mol (SI-enhet). Betecknas n." },
  { id:27,  cat:"Kemiska beräkningar", term:"Molmassa", def:"Massan av ett mol av ett ämne, uttryckt i g/mol; numeriskt lika med atommassan (g/mol = u). Betecknas M." },
  { id:256, cat:"Kemiska beräkningar", term:"Atommassa", def:"Viktat medelvärde av alla naturliga isotopmassor för ett grundämne, relativt ¹²C = 12,000 u. Anges i periodiska systemet." },
  { id:28,  cat:"Kemiska beräkningar", term:"Avogadros konstant", def:"Nₐ = 6,022 × 10²³ mol⁻¹; antalet partiklar i exakt ett mol substans. Koppling: n = N / Nₐ." },
  { id:291, cat:"Kemiska beräkningar", term:"Formmassa", def:"Summan av atommassorna (u) i en formelenhet för ett jonämne eller en molekyl. NaCl: 23 + 35,5 = 58,5 g/mol." },
  { id:95,  cat:"Kemiska beräkningar", term:"Molvolym", def:"Volymen som upptas av exakt ett mol av en idealgas vid STP (0 °C, 1 atm) = 22,4 L/mol." },
  { id:65,  cat:"Kemiska beräkningar", term:"Koncentration", def:"Mängden löst ämne per volymenhet lösning. Vanligast: c = n/V (mol/L). Kan också uttryckas i g/L, masshalt, volymhalt." },
  { id:66,  cat:"Kemiska beräkningar", term:"Molaritet", def:"Koncentration uttryckt i mol löst ämne per liter lösning (mol/L eller M); c = n/V." },
  { id:287, cat:"Kemiska beräkningar", term:"Masshalt", def:"Masshalt = massa löst ämne / massa lösning × 100 %. Enhet: % (w/w). Exempel: saltlake 5 % = 5 g NaCl per 100 g lösning." },
  { id:1003, cat:"Kemiska beräkningar", term:"Massprocent", def:"Synonymt med masshalt; andelen av ett ämne i en blandning räknat i procent av totala massan." },
  { id:1004, cat:"Kemiska beräkningar", term:"Volymhalt", def:"Volym löst ämne / totalvolym lösning × 100 %. Enhet: % (v/v). Används t.ex. för alkoholkoncentration i drycker." },
  { id:69,  cat:"Kemiska beräkningar", term:"Utspädning", def:"Process där koncentrationen minskas genom tillsats av mer lösningsmedel; sambandet: c₁V₁ = c₂V₂." },
  { id:64,  cat:"Kemiska beräkningar", term:"Löst ämne", def:"Det ämne som löses upp i lösningsmedlet; finns i lägre mängd och fördelas jämnt i lösningen." },
  { id:68,  cat:"Kemiska beräkningar", term:"Löslighet", def:"Den maximala mängden av ett ämne som kan lösas i ett givet lösningsmedel vid en bestämd temperatur och tryck." },
  { id:131, cat:"Kemiska beräkningar", term:"Mättad lösning", def:"Lösning som innehåller maximal mängd löst ämne vid given temperatur; ytterligare tillsatt ämne fälls ut." },
  { id:132, cat:"Kemiska beräkningar", term:"Övermättad lösning", def:"Metastabilt tillstånd där mer ämne är löst än normalt möjligt; kristallisering utlöses lätt." },
  { id:141, cat:"Kemiska beräkningar", term:"Standardlösning", def:"Lösning med exakt känd koncentration; framställs vid kalibrering mot en primärstandard; används i titrering." },
  { id:35,  cat:"Kemiska beräkningar", term:"Koefficienter och balansering", def:"Koefficienter framför ämnena i reaktionsformeln anger molförhållandena; justeringen säkerställer att antal atomar och laddning är lika på båda sidor." },
  { id:1005, cat:"Kemiska beräkningar", term:"Stökiometri", def:"Beräkning av kvantitativa förhållanden (mol, massa, volym) mellan reaktanter och produkter i en kemisk reaktion baserat på reaktionsformeln." },
  { id:1006, cat:"Kemiska beräkningar", term:"Substansmängdsförhållande", def:"Förhållandet mellan substansmängderna av reaktanter och produkter i en reaktion; direkt avläsbart från koefficienterna i reaktionsformeln." },
  { id:1007, cat:"Kemiska beräkningar", term:"Ekvivalenta mängder", def:"Substansmängder som reagerar exakt med varandra i ett givet molförhållande; vid ekvivalens finns inget överskott av något reagens." },
  { id:29,  cat:"Kemiska beräkningar", term:"Utbyte", def:"Faktisk mängd produkt jämfört med den teoretiska mängden: utbyte = (faktisk / teoretisk) × 100 %. Aldrig > 100 %." },
  { id:30,  cat:"Kemiska beräkningar", term:"Överskott och begränsande reagens", def:"Begränsande reagens förbrukas först och begränsar produktmängden. Överskott = det reagens som finns i mer än stökiometrisk mängd." },
  { id:1008, cat:"Kemiska beräkningar", term:"Empirisk formel", def:"Enklaste heltalsförhållandet av atomer i ett ämne; t.ex. H₂O (ingen förenkling möjlig), men C₂H₄ → CH₂ empirisk formel." },

  // ══════════════════════════════════════════════
  // Kap 7 – Syror och baser
  // ══════════════════════════════════════════════
  { id:36,  cat:"Syror och baser", term:"Syra", def:"Ämne som donerar protoner (H⁺) enligt Brønsted-Lowry; ökar oxoniumjonkoncentrationen [H₃O⁺] i vattenlösning." },
  { id:37,  cat:"Syror och baser", term:"Bas", def:"Ämne som accepterar protoner (H⁺) enligt Brønsted-Lowry; ökar hydroxidjonkoncentrationen [OH⁻] i lösning." },
  { id:44,  cat:"Syror och baser", term:"Brønsted-Lowry-teorin", def:"Syra-basteori där syror är protondonatorer och baser är protonacceptorer; gäller i alla lösningsmedel, inte bara vatten." },
  { id:152, cat:"Syror och baser", term:"Protolys", def:"Reaktion där ett proton (H⁺) överförs från en protondonator (syra) till en protonacceptor (bas): HA + B ⇌ A⁻ + BH⁺." },
  { id:264, cat:"Syror och baser", term:"Syra-baspar", def:"Två ämnen som skiljer sig med exakt ett H⁺; en syra och dess konjugatbas, t.ex. HCl/Cl⁻ och NH₃/NH₄⁺. I en protolys finns alltid två syra-baspar." },
  { id:155, cat:"Syror och baser", term:"Korresponderande syra-baspar", def:"En syra och dess korresponderande bas skiljer sig med exakt ett H⁺; t.ex. HCl/Cl⁻ och H₂O/OH⁻." },
  { id:150, cat:"Syror och baser", term:"Oxoniumjon", def:"Den hydratiserade protonen i vatten: H₃O⁺. Bildas då en syra avger H⁺ till vatten. Avgör surhet: pH = −log[H₃O⁺]." },
  { id:151, cat:"Syror och baser", term:"Hydroxidjon", def:"OH⁻; negativt laddad jon; bildas vid basers protolys i vatten. [OH⁻] > [H₃O⁺] ger basisk lösning." },
  { id:38,  cat:"Syror och baser", term:"pH-värde", def:"Logaritmiskt mått på oxoniumjonkoncentrationen: pH = −log[H₃O⁺]. Skala 0–14; pH 7 = neutralt, < 7 = surt, > 7 = basiskt (vid 25 °C)." },
  { id:168, cat:"Syror och baser", term:"Surhetsgrad", def:"Mått på en lösnings surhet; pH är vanligaste måttet. Lägre pH = högre surhetsgrad = fler H₃O⁺-joner per liter." },
  { id:156, cat:"Syror och baser", term:"Sur lösning", def:"Vattenlösning där [H₃O⁺] > [OH⁻]; pH < 7 (vid 25 °C)." },
  { id:157, cat:"Syror och baser", term:"Basisk lösning", def:"Vattenlösning där [OH⁻] > [H₃O⁺]; pH > 7 (vid 25 °C)." },
  { id:158, cat:"Syror och baser", term:"Neutral lösning", def:"Vattenlösning där [H₃O⁺] = [OH⁻]; pH = 7 (vid 25 °C)." },
  { id:46,  cat:"Syror och baser", term:"Stark syra", def:"Syra som fullständigt protolyserar i vatten; hög [H₃O⁺]. Exempel: HCl, HNO₃, H₂SO₄, HBr, HI." },
  { id:47,  cat:"Syror och baser", term:"Svag syra", def:"Syra som bara delvis protolyserar i vatten; jämvikt råder. Exempel: ättiksyra (CH₃COOH), koldioxid i vatten, HF." },
  { id:171, cat:"Syror och baser", term:"Stark bas", def:"Bas som fullständigt dissocierar i vatten. Exempel: NaOH, KOH, Ca(OH)₂." },
  { id:172, cat:"Syror och baser", term:"Svag bas", def:"Bas som bara delvis protolyseras i vatten – jämvikt råder. Exempel: NH₃, vatten." },
  { id:163, cat:"Syror och baser", term:"Protolysgrad", def:"Andelen av syra/bas-molekyler som pronolyserats i jämvikt; uttrycks 0–1 eller procent. Hög protolysgrad = stark syra." },
  { id:165, cat:"Syror och baser", term:"Fullständigt protolyserad", def:"Alla syra/bas-molekyler har avgett/tagit emot ett proton; karaktäriserar starka syror (HCl) och baser (NaOH)." },
  { id:166, cat:"Syror och baser", term:"Ofullständigt protolyserad", def:"Bara en del av molekylerna pronolyserats – jämvikt råder; karaktäriserar svaga syror (CH₃COOH) och baser (NH₃)." },
  { id:1100, cat:"Syror och baser", term:"Koncentrerad syra", def:"Syra med hög halt av syrämnet per liter; t.ex. koncentrerad H₂SO₄ (98 %) eller koncentrerad HCl (37 %). Skiljer sig från stark/svag (som anger protolysgrad)." },
  { id:169, cat:"Syror och baser", term:"Enprotonig syra", def:"Syra som avger ett proton per molekyl: t.ex. HCl, HNO₃, CH₃COOH." },
  { id:170, cat:"Syror och baser", term:"Tvåprotonig syra", def:"Syra som kan avge två protoner per molekyl i två steg. Exempel: H₂SO₄, H₂CO₃." },
  { id:45,  cat:"Syror och baser", term:"Amfolyt", def:"Ämne som kan fungera både som syra och bas beroende på motparten; t.ex. vatten (H₂O) och vätekarbonat (HCO₃⁻)." },
  { id:113, cat:"Syror och baser", term:"Vattnets autoprotolys", def:"Reaktion där vatten reagerar med sig självt: 2 H₂O ⇌ H₃O⁺ + OH⁻; jämviktskonstant Kw = 1,0×10⁻¹⁴ vid 25 °C. pH + pOH = 14." },
  { id:105, cat:"Syror och baser", term:"Kemisk jämvikt", def:"Dynamiskt tillstånd där fram- och bakåtreaktionens hastigheter är lika; koncentrationerna är konstanta men inte nödvändigtvis lika." },
  { id:1101, cat:"Syror och baser", term:"Syra-basreaktion", def:"Protolysreaktion där en syra avger ett proton till en bas: HA + B ⇌ A⁻ + HB⁺. Alltid involverar ett utbyte av H⁺ och ett syra-baspar på varje sida." },
  { id:40,  cat:"Syror och baser", term:"Neutralisation", def:"Reaktion mellan syra och bas som bildar salt och vatten: H⁺ + OH⁻ → H₂O; pH → 7 vid fullständig neutralisation av stark syra + stark bas." },
  { id:383, cat:"Syror och baser", term:"Neutralisationsreaktion", def:"Specifik kemisk reaktion mellan en syra och en bas: HA + BOH → BA + H₂O. Exoterm. pH = 7 vid ekvivalenspunkten om stark syra + stark bas." },
  { id:42,  cat:"Syror och baser", term:"Titrering", def:"Kvantitativ analysmetod där en lösning med känd koncentration (titrermedel) tillsätts till analytlösningen tills ekvivalenspunkten nås." },
  { id:173, cat:"Syror och baser", term:"Titrand", def:"Den lösning med okänd koncentration som analyseras vid titrering." },
  { id:174, cat:"Syror och baser", term:"Titrator", def:"Den lösning med känd koncentration (standardlösning) som tillsätts från byretten vid titrering." },
  { id:114, cat:"Syror och baser", term:"Ekvivalenspunkt", def:"Punkten i en titrering där exakt lika antal mol syra och bas har reagerat; påvisas med indikator eller pH-mätare." },
  { id:43,  cat:"Syror och baser", term:"Indikator", def:"Ämne som ändrar färg beroende på pH; används för att visa ekvivalenspunkten vid titrering (t.ex. fenolftalein, BTB, lackmus)." },
  { id:162, cat:"Syror och baser", term:"Omslagsintervall", def:"pH-intervall inom vilket en indikator byter färg. Fenolftalein: 8,2–10,0; BTB: 6,0–7,6; lackmus: 5–8." },
  { id:262, cat:"Syror och baser", term:"Lackmus", def:"Indikator framställd ur lavar. Röd i sur lösning (pH < 5), blå i basisk (pH > 8). Lämplig för snabb surt/basiskt-test." },
  { id:263, cat:"Syror och baser", term:"Bromtymolblått (BTB)", def:"Indikator med omslagsintervall pH 6,0–7,6. Gul i surt, grön vid neutralt (~7), blå i basiskt. Lämplig vid titrering av stark syra mot stark bas." },
  { id:175, cat:"Syror och baser", term:"Buffertlösning", def:"Lösning som motstår pH-förändringar vid tillsats av syra eller bas; innehåller en svag syra och dess konjugatbas. Blodets pH (≈7,4) buffras av H₂CO₃/HCO₃⁻." },
  { id:167, cat:"Syror och baser", term:"SIV-regeln", def:"Minnesregel vid balansering av redoxreaktioner i sur lösning: S=Syre med H₂O, I=väte med H⁺, V=laddning med e⁻." },
  { id:117, cat:"Syror och baser", term:"Proton (H⁺)", def:"Vätejon (H⁺); i vattenlösning hydratiserad som H₃O⁺; central partikel i Brønsted-Lowry-teorin om syror och baser." },
  { id:142, cat:"Syror och baser", term:"pH-meter", def:"Elektroinstrument för exakt mätning av pH via en glaselektrod; kalibreras mot buffertlösningar med känt pH." },
  { id:230, cat:"Syror och baser", term:"HCl – Saltsyra", def:"Stark syra. HCl → H⁺ + Cl⁻ (fullständig). Finns i magsäcken. Frätande." },
  { id:231, cat:"Syror och baser", term:"H₂SO₄ – Svavelsyra", def:"Stark tvåprotonig syra. Starkt korrosiv. Bilbatterier och gödselproduktion." },
  { id:232, cat:"Syror och baser", term:"HNO₃ – Salpetersyra", def:"Stark syra och starkt oxidationsmedel. Reagerar med de flesta metaller." },
  { id:233, cat:"Syror och baser", term:"HBr – Bromvätesyra", def:"Stark halogenvätesyra. HBr → H⁺ + Br⁻ (fullständig)." },
  { id:234, cat:"Syror och baser", term:"HI – Jodvätesyra", def:"Stark halogenvätesyra. HI → H⁺ + I⁻. Starkt reduceringsmedel." },
  { id:235, cat:"Syror och baser", term:"CH₃COOH – Ättiksyra", def:"Svag syra. pKa = 4,75. Finns i vinäger (5–8 %). Konjugatbas: CH₃COO⁻ (acetat)." },
  { id:236, cat:"Syror och baser", term:"HF – Fluorvätesyra", def:"Svag syra (pKa ≈ 3,2). Farlig – angriper benvävnad och glas. Kräver specialhantering." },
  { id:237, cat:"Syror och baser", term:"H₂CO₃ – Kolsyra", def:"Svag tvåprotonig syra. CO₂ + H₂O ⇌ H₂CO₃. Viktig buffert i blodet." },
  { id:238, cat:"Syror och baser", term:"H₃PO₄ – Fosforsyra", def:"Svag treprotonig syra. pKa₁ ≈ 2,1. Ingår i läskedrycker." },
  { id:239, cat:"Syror och baser", term:"NaOH – Natriumhydroxid", def:"Stark bas. NaOH → Na⁺ + OH⁻. Starkt frätande. Kallas lut. Används vid tvål- och papperstillverkning." },
  { id:240, cat:"Syror och baser", term:"KOH – Kaliumhydroxid", def:"Stark bas. KOH → K⁺ + OH⁻. Liknande NaOH. Alkaliska batterier." },
  { id:241, cat:"Syror och baser", term:"Ca(OH)₂ – Kalciumhydroxid", def:"Stark men svagt löslig bas. pH ≈ 12,4 (mättat). Kalkvatten. Cement och jordbruk." },
  { id:242, cat:"Syror och baser", term:"NH₃ – Ammoniak", def:"Svag bas. NH₃ + H₂O ⇌ NH₄⁺ + OH⁻. Skarp lukt. Gödningsmedel och rengöring." },

  // ══════════════════════════════════════════════
  // Kap 8 – Energi och kemi
  // ══════════════════════════════════════════════
  { id:1200, cat:"Energi och kemi", term:"Energi", def:"Förmåga att utföra arbete eller framkalla förändringar; i kemin omvandlas kemisk energi till värme/rörelse vid reaktioner. Enhet: joule (J)." },
  { id:72,   cat:"Energi och kemi", term:"Entalpi", def:"Termodynamisk tillståndsfunktion H = U + pV; vid konstant tryck är ΔH = värmeutbytet med omgivningen. Enhet: kJ/mol." },
  { id:75,   cat:"Energi och kemi", term:"Entalpiändring", def:"ΔH = H(produkter) − H(reaktanter); negativt ΔH = exoterm reaktion (värme frigörs); positivt ΔH = endoterm (värme absorberas)." },
  { id:73,   cat:"Energi och kemi", term:"Exoterm reaktion", def:"Reaktion som frigör värme till omgivningen; ΔH < 0. Temperaturen i reaktionsblandningen stiger. Exempel: förbränning, neutralisation." },
  { id:74,   cat:"Energi och kemi", term:"Endoterm reaktion", def:"Reaktion som absorberar värme från omgivningen; ΔH > 0. Temperaturen i reaktionsblandningen sjunker. Exempel: fotosyntes, smältning." },
  { id:135,  cat:"Energi och kemi", term:"Bildningsentalpi", def:"Entalpiskillnaden ΔHf° vid bildning av 1 mol av ett ämne från sina grundämnen i standardtillstånd (25 °C, 1 bar). Enhet: kJ/mol." },
  { id:77,   cat:"Energi och kemi", term:"Bindningsenergi", def:"Den energi som krävs för att bryta en kemisk bindning i gasform; frigörs vid bindningsbildning. Reaktionsentalpi ≈ ΣBindEnerg(brutna) − ΣBindEnerg(bildade)." },
  { id:1201, cat:"Energi och kemi", term:"Kemisk energi", def:"Energi lagrad i kemiska bindningar; frigörs eller absorberas vid reaktioner. Källan till energi i mat, bränsle och batterier." },
  { id:138,  cat:"Energi och kemi", term:"Energiinnehåll", def:"Den energimängd (kJ/g eller kJ/mol) som frigörs vid fullständig förbränning av ett ämne; mäts med kalorimeter." },
  { id:382,  cat:"Energi och kemi", term:"Förbränningsreaktion", def:"Exoterm reaktion med syre (O₂) som producerar CO₂ och H₂O; kräver bränsle, syre och antändningsenergi. Fullständig: CH₄ + 2O₂ → CO₂ + 2H₂O." },
  { id:103,  cat:"Energi och kemi", term:"Aktiveringsenergi", def:"Den minsta energi reaktanter måste ha för att en reaktion ska kunna ske; symbol Eₐ; sänks av katalysatorer." },
  { id:102,  cat:"Energi och kemi", term:"Katalysator", def:"Ämne som ökar reaktionshastigheten utan att förbrukas; sänker aktiveringsenergin genom alternativ reaktionsväg." },
  { id:78,   cat:"Energi och kemi", term:"Kalorimeter", def:"Instrument för att mäta värmeutbytet vid kemiska reaktioner: Q = m·c·ΔT. Isolerat kärl hindrar värmeförlust till omgivningen." },
  { id:79,   cat:"Energi och kemi", term:"Specifik värmekapacitet", def:"Energin som krävs för att höja temperaturen hos 1 kg av ett ämne med 1 K; enhet J/(kg·K). Vatten: 4 186 J/(kg·K)." },
  { id:1202, cat:"Energi och kemi", term:"Värmeenergi", def:"Energi som överförs på grund av temperaturskillnad; flödar alltid från varmare till kallare objekt. Q = m·c·ΔT." },
  { id:1203, cat:"Energi och kemi", term:"Temperatur", def:"Mått på den genomsnittliga kinetiska energin hos partiklar; enhet kelvin (K) eller celsius (°C). T(K) = T(°C) + 273,15." },
  { id:1204, cat:"Energi och kemi", term:"Värmeförlust", def:"Energi som läcker ut till omgivningen under ett experiment; systematisk felkälla vid kalorimetrimätningar som ger lägre uppmätt ΔH." },
  { id:1205, cat:"Energi och kemi", term:"Entropi", def:"Mått på oordningen i ett system; symbol S. Processer sker spontant om entropin ökar i universum (ΔS_universum > 0). Enhet: J/(mol·K)." },
  { id:1206, cat:"Energi och kemi", term:"Oordning", def:"Vardaglig beskrivning av entropi; kemiska system tenderar att gå mot ökad oordning (gasblandning, upplösning). Kopplat till spontana processer." },
  { id:1207, cat:"Energi och kemi", term:"Spontan reaktion", def:"Reaktion som sker av sig självt utan tillförsel av energi; beror på att fri energi minskar (ΔG < 0); gynnas av exoterm process och/eller ökad entropi." },
  { id:281,  cat:"Energi och kemi", term:"Växthuseffekt", def:"Ökad halt av växthusgaser (CO₂, CH₄, N₂O) i atmosfären → mer IR-strålning absorberas → jordytan värms upp (global uppvärmning)." },

  // ══════════════════════════════════════════════
  // Kap 9 – Reduktion och oxidation
  // ══════════════════════════════════════════════
  { id:31,  cat:"Reduktion och oxidation", term:"Oxidationstal", def:"Formellt laddningstal på en atom i en förening, beräknat utifrån elektronegativiteten. Ren metall = 0; O vanligen −2; H vanligen +1." },
  { id:32,  cat:"Reduktion och oxidation", term:"Oxidation", def:"Förlust av elektroner eller ökning av oxidationstal; sker alltid tillsammans med reduktion i en redoxreaktion." },
  { id:33,  cat:"Reduktion och oxidation", term:"Reduktion", def:"Vinst av elektroner eller minskning av oxidationstal; sker alltid tillsammans med oxidation i en redoxreaktion." },
  { id:34,  cat:"Reduktion och oxidation", term:"Redoxreaktioner", def:"Reaktioner där elektroner överförs mellan ämnen; oxidationsmedlet reduceras och reduktionsmedlet oxideras." },
  { id:1300, cat:"Reduktion och oxidation", term:"Elektronövergång", def:"Överföring av en eller fler elektroner från ett ämne (reduktionsmedel) till ett annat (oxidationsmedel); kärnan i alla redoxreaktioner." },
  { id:288, cat:"Reduktion och oxidation", term:"Oxidationsmedel", def:"Ämne som tar upp elektroner och reduceras själv i en redoxreaktion. Exempel: O₂, Cl₂, Cu²⁺, MnO₄⁻. Stark oxidant = hög reduktionspotential." },
  { id:289, cat:"Reduktion och oxidation", term:"Reduktionsmedel", def:"Ämne som avger elektroner och oxideras själv i en redoxreaktion. Exempel: Zn, Al, H₂, Na. Starka reduktionsmedel återfinns tidigt i spänningsserien." },
  { id:1301, cat:"Reduktion och oxidation", term:"Oxidationstalsmetoden", def:"Metod för att balansera redoxreaktioner: identifiera oxidationstalens ändringar, multiplicera halvreaktionerna så att elektroner jämnas ut." },
  { id:1302, cat:"Reduktion och oxidation", term:"Elektronövergångsmetoden", def:"Metod för att balansera redoxreaktioner via separata halvreaktioner (oxidation och reduktion); elektroner lika på båda sidor." },
  { id:1303, cat:"Reduktion och oxidation", term:"Oxidationstalsändring", def:"Skillnaden i oxidationstal före och efter reaktion; oxidationsmedlet minskar sitt tal (reduceras), reduktionsmedlet ökar (oxideras)." },
  { id:292, cat:"Reduktion och oxidation", term:"Åskådarjoner", def:"Joner som finns i lösning men inte deltar i redoxreaktionen; utesluts i nettojonsreaktionen. Exempel: Na⁺ och NO₃⁻ vid fällning av AgCl." },
  { id:402, cat:"Reduktion och oxidation", term:"Katod", def:"Elektroden där reduktion sker; elektroner tas emot. Minnesregel: RedKat – Reduktion vid Katoden." },
  { id:403, cat:"Reduktion och oxidation", term:"Anod", def:"Elektroden där oxidation sker; elektroner avges. Minnesregel: OxAn – Oxidation vid Anoden." },
  { id:1304, cat:"Reduktion och oxidation", term:"Katjon", def:"Positivt laddad jon (cation) som bildas när en atom förlorar elektroner; rör sig mot katoden vid elektrolys. Exempel: Na⁺, Ca²⁺, Cu²⁺." },
  { id:1305, cat:"Reduktion och oxidation", term:"Anjon", def:"Negativt laddad jon (anion) som bildas när en atom tar upp elektroner; rör sig mot anoden vid elektrolys. Exempel: Cl⁻, SO₄²⁻, OH⁻." },
  { id:243, cat:"Reduktion och oxidation", term:"Galvanisk cell", def:"Elektrokemisk cell som omvandlar en spontan redoxreaktion till elektrisk energi. Anod (−) = oxidation, katod (+) = reduktion. Exempel: Daniells element (Zn/Cu)." },
  { id:1306, cat:"Reduktion och oxidation", term:"Halvcell", def:"En elektrod med tillhörande lösning; representerar en halvreaktion (enbart oxidation eller reduktion). En galvanisk cell består av två halvceller." },
  { id:253, cat:"Reduktion och oxidation", term:"Cellschema", def:"Standardnotation: Zn(s)|Zn²⁺(aq)||Cu²⁺(aq)|Cu(s). Enkelt streck | = fasövergång; dubbelt streck || = saltbrygga. Vänster = anod, höger = katod." },
  { id:1307, cat:"Reduktion och oxidation", term:"Saltbrygga", def:"Jonledande bro (t.ex. KCl-gel i ett U-rör) mellan de två halvcellerna i ett galvaniskt element; upprätthåller elektrisk neutralitet i lösningarna." },
  { id:244, cat:"Reduktion och oxidation", term:"Normalpotential", def:"Reduktionspotential under standardförhållanden (25 °C, 1 mol/L, 1 atm) mätt mot normalvätgaselektroden (E° = 0,00 V). Hög positiv E° = ädel, reduceras gärna." },
  { id:245, cat:"Reduktion och oxidation", term:"Spänningsserien", def:"Rangordning av metaller och halvreaktioner efter stigande E°. Ädla metaller längst upp; reaktiva längst ner. Styr vilka spontana redoxreaktioner som kan ske." },
  { id:254, cat:"Reduktion och oxidation", term:"Redoxpar", def:"Oxiderad och reducerad form av ett ämne: Ox/Red, t.ex. Cu²⁺/Cu och Zn/Zn²⁺. De två redoxparen utbyter elektroner i galvanisk cell." },
  { id:129, cat:"Reduktion och oxidation", term:"Elektrolyt", def:"Ämne som bildar joner i lösning och därigenom leder elektrisk ström; stark elektrolyt dissocierar fullständigt (t.ex. NaCl); svag elektrolyt delvis." },
  { id:255, cat:"Reduktion och oxidation", term:"Elektrolys", def:"Icke-spontan kemisk reaktion driven av extern elektrisk ström. Katod (−) = reduktion av katjoner; anod (+) = oxidation. Exempel: framställning av Al, Cl₂." },
  { id:1308, cat:"Reduktion och oxidation", term:"Smältelektrolys", def:"Elektrolys av ett smält (upphettat) jonämne utan lösningsmedel; används för att framställa reaktiva metaller som Al och Na ur sina oxider/klorider." },
  { id:249, cat:"Reduktion och oxidation", term:"Korrosion", def:"Elektrokemisk nedbrytning av en metall genom oxidation. Järnrost: 4Fe + 3O₂ → 2Fe₂O₃. Kräver fukt och syre; accelereras av kontakt med ädlare metall (galvanisk korrosion)." },
  { id:1309, cat:"Reduktion och oxidation", term:"Korrosionsskydd", def:"Metoder för att hindra korrosion: målning/lackering, galvanisering (Zn-beläggning), passivering (Al₂O₃), katodiskt skydd (offeranod)." },
  { id:251, cat:"Reduktion och oxidation", term:"Offeranod", def:"Mer oädel metall (Zn eller Mg) som ansluts till konstruktionen och korroderar istället; skyddar stål/järn. Används på fartyg, rörledningar och betongpålar." },
  { id:252, cat:"Reduktion och oxidation", term:"Passivering", def:"Spontan bildning av ett skyddande oxidskikt på metallyta: Al₂O₃ på aluminium, Cr₂O₃ på rostfritt stål; hindrar vidare korrosion." },
  { id:1310, cat:"Reduktion och oxidation", term:"Lokalelement", def:"Korrosionscell som bildas på en metalls yta med ojämnheter; anodiska och katodiska områden bildas lokalt → accelererad lokal korrosion." },
  { id:404, cat:"Reduktion och oxidation", term:"Katod i galvaniskt element", def:"Reduktion vid katoden; katoden är positiv pol (+) och tar emot elektroner. Exempel: Cu²⁺ + 2e⁻ → Cu i Daniell-cellen." },
  { id:405, cat:"Reduktion och oxidation", term:"Anod i galvaniskt element", def:"Oxidation vid anoden; anoden är negativ pol (−) och avger elektroner. Exempel: Zn → Zn²⁺ + 2e⁻ i Daniell-cellen." },
  { id:406, cat:"Reduktion och oxidation", term:"Elektrolyscell vs galvanisk cell", def:"Galvaniskt element: anod = −, katod = +. Elektrolyscell: anod kopplad till +, katod till −. I båda: oxidation vid anod, reduktion vid katod." },
  { id:407, cat:"Reduktion och oxidation", term:"Elektronflöde i yttre krets", def:"Elektroner flödar alltid från anod till katod i yttre kretsen; lämnar anoden (oxidation) och anländer till katoden (reduktion)." },
  { id:408, cat:"Reduktion och oxidation", term:"RedKat och OxAn", def:"RedKat = Reduktion vid Katoden. OxAn = Oxidation vid Anoden. Gäller i alla typer av elektrokemiska celler." },
  { id:1311, cat:"Reduktion och oxidation", term:"Alkaliskt batteri", def:"Galvanisk cell med zink (anod) och mangandioxid (katod) i alkalisk elektrolyt (KOH); ger 1,5 V; vanligaste engångsbatteriet." },
  { id:1312, cat:"Reduktion och oxidation", term:"Litiumbatteri", def:"Batteri med litiumanod och hög energidensitet; ger 3–4 V. Litiumjonbatterier (uppladdningsbara) används i mobiltelefoner och elbilar." },
  { id:1313, cat:"Reduktion och oxidation", term:"Blyackumulator", def:"Uppladdningsbart batteri (ackumulator) med bly-anod, PbO₂-katod och H₂SO₄ som elektrolyt; ger 12 V (6 celler × 2 V). Används i startbatterier för bilar." },
  { id:1314, cat:"Reduktion och oxidation", term:"Bränslecell", def:"Elektrokemisk cell som omvandlar kemisk energi (t.ex. H₂ + O₂) direkt till el utan förbränning; bildar bara vatten. Hög verkningsgrad (~60 %)." },
  { id:1315, cat:"Reduktion och oxidation", term:"Strömdrivande reaktion", def:"Spontan redoxreaktion som driver elektrisk ström i ett galvaniskt element; reaktionen har negativ fri energi (ΔG < 0)." },
  { id:1316, cat:"Reduktion och oxidation", term:"Väteutdrivande", def:"Egenskap hos oädla metaller (t.ex. Zn, Fe, Al) att reagera med syralösning och driva ut vätgas: Zn + H₂SO₄ → ZnSO₄ + H₂↑." },

];

